import React, { useState } from "react";
import "../css/userDashboard.css";
import {
  FaUser, FaHeart, FaCalendarAlt, FaCog,
  FaMapMarkerAlt, FaBed, FaBath, FaSignOutAlt,
  FaCheckCircle, FaClock, FaTimesCircle, FaEdit,
  FaCamera, FaPhone, FaEnvelope, FaMobileAlt,
  FaArrowRight, FaTrash, FaBell, FaShieldAlt,
  FaHome, FaChevronRight
} from "react-icons/fa";

import API from "../utils/api";
import { useAuth } from "../context/AuthContext";
import { useNavigate } from "react-router-dom";

/* ─── MOCK USER ─── */
const USER = {
  name: "Subash R",
  email: "rt.subash@gmail.com",
  mobile: "+91 97877 51663",
  
  role: "Tenant",
  joinedDate: "April 2026",
  verified: true,
};

/* ─── SAVED PROPERTIES ─── */
const SAVED = [
  { id:9,  title:"3BHK Luxury Apartment", location:"Saravanampatti", price:20000, beds:3, baths:2, type:"Apartment", image:"https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=400&q=80" },
  { id:1,  title:"2BHK Independent House", location:"Peelamedu",    price:15000, beds:2, baths:1, type:"House",     image:"https://images.unsplash.com/photo-1560185127-6ed189bf02f4?w=400&q=80" },
  { id:11, title:"2BHK Modern Apartment",  location:"Gandhipuram",  price:14000, beds:2, baths:2, type:"Apartment", image:"https://images.unsplash.com/photo-1512917774080-9991f1c4c750?w=400&q=80" },
];

/* ─── BOOKINGS ─── */
const BOOKINGS = [
  {
    id:"BK001", title:"3BHK Luxury Apartment", location:"Saravanampatti",
    price:20000, type:"Apartment", status:"confirmed",
    bookedOn:"Mar 10, 2026", visitDate:"Mar 25, 2026",
    owner:"Dhanuj", image:"https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=400&q=80"
  },
  {
    id:"BK002", title:"2BHK House", location:"Peelamedu",
    price:15000, type:"House", status:"pending",
    bookedOn:"Mar 15, 2026", visitDate:"Mar 28, 2026",
    owner:"Dinesh", image:"https://images.unsplash.com/photo-1560185127-6ed189bf02f4?w=400&q=80"
  },
  {
    id:"BK003", title:"Men's PG Room", location:"Gandhipuram",
    price:7000, type:"PG", status:"cancelled",
    bookedOn:"Feb 20, 2026", visitDate:"Feb 25, 2026",
    owner:"Vishal", image:"https://images.unsplash.com/photo-1507089947368-19c1da9775ae?w=400&q=80"
  },
];

const STATUS_CONFIG = {
  confirmed: { icon:<FaCheckCircle />, label:"Confirmed", cls:"confirmed" },
  pending:   { icon:<FaClock />,       label:"Pending",   cls:"pending"   },
  cancelled: { icon:<FaTimesCircle />, label:"Cancelled", cls:"cancelled" },
};

const TABS = [
  { key:"overview",   label:"Overview",   icon:<FaHome /> },
  { key:"saved",      label:"Saved",      icon:<FaHeart /> },
  { key:"bookings",   label:"Bookings",   icon:<FaCalendarAlt /> },
  { key:"settings",   label:"Settings",   icon:<FaCog /> },
];

export default function UserDashboard() {
  const [activeTab, setActiveTab]     = useState("overview");
  const [saved, setSaved]             = useState(SAVED);
  const [editMode, setEditMode]       = useState(false);
  const [profile, setProfile]         = useState({
    name: USER.name, email: USER.email, mobile: USER.mobile,
  });
  const [notifications, setNotifications] = useState({
    email: true, sms: true, bookingUpdates: true, newListings: false,
  });

  const removeFromSaved = (id) => setSaved(prev => prev.filter(p => p.id !== id));

  const handleProfileSave = () => setEditMode(false);

  const { user, logout } = useAuth();
  const navigate         = useNavigate();

  const [bookings,  setBookings]  = useState([]);
  const [savedProps, setSavedProps] = useState([]);
  const [loading,   setLoading]   = useState(true);


  useEffect(() => {
  fetchData();
}, []);

const fetchData = async () => {
  try {
    setLoading(true);

    // Get bookings
    const bookingRes = await API.get("/bookings/user");
    setBookings(bookingRes.data.bookings);

    // Get wishlist
    const wishlistRes = await API.get("/wishlist");
    setSavedProps(wishlistRes.data.wishlist);

  } catch (err) {
    console.error("Dashboard error:", err);
  } finally {
    setLoading(false);
  }
};

  return (
    <div className="ud-root">

      {/* ── NAVBAR ── */}
      <nav className="ud-nav">
        <a href="/" className="ud-logo">RentSpace</a>
        <div className="ud-nav-links">
          <a href="/">Home</a>
          <a href="/listings">Rentals</a>
          <a href="/login" className="ud-logout">
            <FaSignOutAlt /> Logout
          </a>
        </div>
      </nav>

      <div className="ud-body">

        {/* ── SIDEBAR ── */}
        <aside className="ud-sidebar">

          {/* PROFILE SUMMARY */}
          <div className="ud-profile-summary">
            <div className="ud-avatar-wrap">
              <img src={USER.avatar} alt={USER.name} />
              <button className="ud-avatar-edit"><FaCamera /></button>
            </div>
            <h3>{user?.username}</h3>
            <p className="ud-role">{USER.role}</p>
            {USER.verified && (
              <div className="ud-verified"><FaCheckCircle /> Verified Account</div>
            )}
            <p className="ud-joined">Member since {USER.joinedDate}</p>
          </div>

          {/* STATS */}
          <div className="ud-sidebar-stats">
            <div className="ud-sidebar-stat">
              <strong>{saved.length}</strong>
              <span>Saved</span>
            </div>
            <div className="ud-sidebar-stat">
              <strong>{BOOKINGS.length}</strong>
              <span>Bookings</span>
            </div>
            <div className="ud-sidebar-stat">
              <strong>{BOOKINGS.filter(b => b.status === "confirmed").length}</strong>
              <span>Confirmed</span>
            </div>
          </div>

          {/* NAV TABS */}
          <nav className="ud-sidebar-nav">
            {TABS.map(t => (
              <button
                key={t.key}
                className={`ud-nav-item ${activeTab === t.key ? "active" : ""}`}
                onClick={() => setActiveTab(t.key)}
              >
                <span className="ud-nav-icon">{t.icon}</span>
                {t.label}
                <FaChevronRight className="ud-nav-arrow" />
              </button>
            ))}
          </nav>

          {/* LOGOUT */}
          <button
  className="ud-sidebar-logout"
  onClick={handleLogout}
>
  <FaSignOutAlt /> Sign Out
</button>

        </aside>

        {/* ── MAIN CONTENT ── */}
        <main className="ud-main">

          {/* ══ OVERVIEW TAB ══ */}
          {activeTab === "overview" && (
            <div className="ud-tab-content">
              <div className="ud-tab-header">
                <h2>Welcome Back, <em>{USER.name.split(" ")[0]}</em> 👋</h2>
                <p>Here's a Summary of Your Activity</p>
              </div>

              {/* STAT CARDS */}
              <div className="ud-stat-cards">
                {[
                  { icon:<FaHeart />,       label:"Saved Properties", val:saved.length,                                color:"accent"  },
                  { icon:<FaCalendarAlt />, label:"Total Bookings",    val:BOOKINGS.length,                             color:"accent2" },
                  { icon:<FaCheckCircle />, label:"Confirmed",         val:BOOKINGS.filter(b=>b.status==="confirmed").length, color:"green" },
                  { icon:<FaClock />,       label:"Pending",           val:BOOKINGS.filter(b=>b.status==="pending").length,   color:"yellow" },
                ].map(s => (
                  <div key={s.label} className={`ud-stat-card ud-stat-${s.color}`}>
                    <div className="ud-stat-icon">{s.icon}</div>
                    <div>
                      <strong>{s.val}</strong>
                      <span>{s.label}</span>
                    </div>
                  </div>
                ))}
              </div>

              {/* RECENT BOOKINGS */}
              <div className="ud-section">
                <div className="ud-section-header">
                  <h3>Recent Bookings</h3>
                  <button className="ud-see-all" onClick={() => setActiveTab("bookings")}>
                    See All <FaArrowRight />
                  </button>
                </div>
                <div className="ud-recent-list">
                  {BOOKINGS.slice(0,2).map(b => {
                    const st = STATUS_CONFIG[b.status];
                    return (
                      <div key={b.id} className="ud-recent-item">
                        <img src={b.image} alt={b.title} />
                        <div className="ud-recent-info">
                          <h4>{b.title}</h4>
                          <p><FaMapMarkerAlt /> {b.location}</p>
                        </div>
                        <div className={`ud-status-badge ${st.cls}`}>
                          {st.icon} {st.label}
                        </div>
                        <p className="ud-recent-price">₹{b.price.toLocaleString()}/mo</p>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* SAVED QUICK VIEW */}
              <div className="ud-section">
                <div className="ud-section-header">
                  <h3>Saved Properties</h3>
                  <button className="ud-see-all" onClick={() => setActiveTab("saved")}>
                    See All <FaArrowRight />
                  </button>
                </div>
                <div className="ud-saved-mini-grid">
                  {saved.slice(0,3).map(p => (
                    <div key={p.id} className="ud-saved-mini-card">
                      <img src={p.image} alt={p.title} />
                      <div className="ud-saved-mini-info">
                        <h4>{p.title}</h4>
                        <p><FaMapMarkerAlt /> {p.location}</p>
                        <span>₹{p.price.toLocaleString()}/mo</span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {/* ══ SAVED TAB ══ */}
          {activeTab === "saved" && (
            <div className="ud-tab-content">
              <div className="ud-tab-header">
                <h2>Saved Properties</h2>
                <p>{saved.length} Properties Saved</p>
              </div>

              {saved.length === 0 ? (
                <div className="ud-empty">
                  <FaHeart />
                  <h3>No saved properties</h3>
                  <p>Go to listings and save properties you like!</p>
                  <a href="/listings" className="ud-empty-btn">Browse Listings <FaArrowRight /></a>
                </div>
              ) : (
                <div className="ud-saved-grid">
                  {saved.map(p => (
                    <div key={p.id} className="ud-saved-card">
                      <div className="ud-saved-img-wrap">
                        <img src={p.image} alt={p.title} />
                        <span className="ud-saved-type">{p.type}</span>
                        <button
                          className="ud-remove-saved"
                          onClick={() => removeFromSaved(p.id)}
                          title="Remove from saved"
                        >
                          <FaTrash />
                        </button>
                      </div>
                      <div className="ud-saved-info">
                        <h4>{p.title}</h4>
                        <p className="ud-saved-loc"><FaMapMarkerAlt /> {p.location}, Coimbatore</p>
                        <div className="ud-saved-meta">
                          <span><FaBed /> {p.beds} Beds</span>
                          <span><FaBath /> {p.baths} Baths</span>
                        </div>
                        <div className="ud-saved-footer">
                          <span className="ud-saved-price">₹{p.price.toLocaleString()}<small>/mo</small></span>
                          <a href={`/property/${p.id}`} className="ud-view-btn">
                            View <FaArrowRight />
                          </a>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* ══ BOOKINGS TAB ══ */}
          {activeTab === "bookings" && (
            <div className="ud-tab-content">
              <div className="ud-tab-header">
                <h2>My Bookings</h2>
                <p>{BOOKINGS.length} total bookings</p>
              </div>

              <div className="ud-bookings-list">
                {BOOKINGS.map(b => {
                  const st = STATUS_CONFIG[b.status];
                  return (
                    <div key={b.id} className={`ud-booking-card ud-booking-${b.status}`}>
                      <img src={b.image} alt={b.title} className="ud-booking-img" />
                      <div className="ud-booking-info">
                        <div className="ud-booking-top">
                          <div>
                            <h4>{b.title}</h4>
                            <p><FaMapMarkerAlt /> {b.location}, Coimbatore</p>
                          </div>
                          <div className={`ud-status-badge ${st.cls}`}>
                            {st.icon} {st.label}
                          </div>
                        </div>
                        <div className="ud-booking-meta">
                          <div className="ud-booking-meta-item">
                            <span>Booking ID</span>
                            <strong>{b.id}</strong>
                          </div>
                          <div className="ud-booking-meta-item">
                            <span>Booked On</span>
                            <strong>{b.bookedOn}</strong>
                          </div>
                          <div className="ud-booking-meta-item">
                            <span>Visit Date</span>
                            <strong>{b.visitDate}</strong>
                          </div>
                          <div className="ud-booking-meta-item">
                            <span>Owner</span>
                            <strong>{b.owner}</strong>
                          </div>
                          <div className="ud-booking-meta-item">
                            <span>Monthly Rent</span>
                            <strong className="ud-booking-price">₹{b.price.toLocaleString()}</strong>
                          </div>
                          <div className="ud-booking-meta-item">
                            <span>Type</span>
                            <strong>{b.type}</strong>
                          </div>
                        </div>
                        <div className="ud-booking-actions">
                          <a href={`/property/${b.id}`} className="ud-bk-view-btn">
                            View Property <FaArrowRight />
                          </a>
                          <a href="/chat" className="ud-bk-chat-btn">
                            Chat Owner
                          </a>
                          {b.status === "pending" && (
                            <button className="ud-bk-cancel-btn">Cancel</button>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* ══ SETTINGS TAB ══ */}
          {activeTab === "settings" && (
            <div className="ud-tab-content">
              <div className="ud-tab-header">
                <h2>Account Settings</h2>
                <p>Manage Your Profile and Preferences</p>
              </div>

              {/* PROFILE EDIT */}
              <div className="ud-settings-section">
                <div className="ud-settings-section-header">
                  <div>
                    <h3><FaUser /> Personal Information</h3>
                    <p>Update Your Profile Details</p>
                  </div>
                  <button
                    className="ud-edit-btn"
                    onClick={() => editMode ? handleProfileSave() : setEditMode(true)}
                  >
                    {editMode ? <><FaCheckCircle /> Save</> : <><FaEdit /> Edit</>}
                  </button>
                </div>

                <div className="ud-profile-form">
                  <div className="ud-form-row">
                    <div className="ud-form-field">
                      <label><FaUser /> Full Name</label>
                      <input
                        type="text"
                        value={profile.name}
                        disabled={!editMode}
                        onChange={e => setProfile(p => ({...p, name: e.target.value}))}
                      />
                    </div>
                    <div className="ud-form-field">
                      <label><FaEnvelope /> Email Address</label>
                      <input
                        type="email"
                        value={profile.email}
                        disabled={!editMode}
                        onChange={e => setProfile(p => ({...p, email: e.target.value}))}
                      />
                    </div>
                  </div>
                  <div className="ud-form-row">
                    <div className="ud-form-field">
                      <label><FaMobileAlt /> Mobile Number</label>
                      <input
                        type="text"
                        value={profile.mobile}
                        disabled={!editMode}
                        onChange={e => setProfile(p => ({...p, mobile: e.target.value}))}
                      />
                    </div>
                    <div className="ud-form-field">
                      <label><FaShieldAlt /> Account Type</label>
                      <input type="text" value={USER.role} disabled />
                    </div>
                  </div>
                </div>
              </div>

              {/* NOTIFICATIONS */}
              <div className="ud-settings-section">
                <div className="ud-settings-section-header">
                  <div>
                    <h3><FaBell /> Notification Preferences</h3>
                    <p>Choose What Notifications You Receive</p>
                  </div>
                </div>
                <div className="ud-notif-list">
                  {[
                    { key:"email",          label:"Email Notifications",      desc:"Receive updates via email" },
                    { key:"sms",            label:"SMS Notifications",         desc:"Receive updates via SMS" },
                    { key:"bookingUpdates", label:"Booking Status Updates",    desc:"Get notified on booking changes" },
                    { key:"newListings",    label:"New Listings Alert",        desc:"Get notified when new properties are added" },
                  ].map(n => (
                    <div key={n.key} className="ud-notif-item">
                      <div>
                        <strong>{n.label}</strong>
                        <p>{n.desc}</p>
                      </div>
                      <label className="ud-toggle">
                        <input
                          type="checkbox"
                          checked={notifications[n.key]}
                          onChange={e => setNotifications(prev => ({...prev, [n.key]: e.target.checked}))}
                        />
                        <span className="ud-toggle-track">
                          <span className="ud-toggle-thumb" />
                        </span>
                      </label>
                    </div>
                  ))}
                </div>
              </div>

              {/* DANGER ZONE */}
              <div className="ud-settings-section ud-danger-zone">
                <h3>Danger Zone</h3>
                <div className="ud-danger-actions">
                  <div>
                    <strong>Delete Account</strong>
                    <p>Permanently Delete Your Account and All Data</p>
                  </div>
                  <button className="ud-delete-btn">Delete Account</button>
                </div>
              </div>

            </div>
          )}

        </main>
      </div>
    </div>
  );
}
